@Override
public float floatValue() {
    if (numerator.equals(BigInteger.ZERO)) {
        return 0.0f;
    }

    // Determine if values are too large for direct conversion
    int numBits = numerator.bitLength();
    int denBits = denominator.bitLength();

    if (numBits > 128 || denBits > 128) {
        // For very large numbers, calculate the appropriate shift to keep 
        // both numbers within the range of float values while preserving ratio
        int maxBits = Math.max(numBits, denBits);
        int shift = maxBits - 100; // Leave a safe margin (max for float is ~128)

        if (shift > 0) {
            return numerator.shiftRight(shift).floatValue() / 
                   denominator.shiftRight(shift).floatValue();
        } else {
            return numerator.floatValue() / denominator.floatValue();
        }
    }

    return numerator.floatValue() / denominator.floatValue();
}

